-use crate::model::ProofTree;
+/// One node: its step line, then its case layout (see module docs).
+fn render_node(
+    lines: &mut Vec<String>,
+    index: u64,
+    lemma: &str,
+    sub: &mut Vec<String>,
+    node: &ProofTree,
+    depth: usize,
