28	/// Slice the three producer slots out of a captured index page.
29	fn invert_index(page: &str) -> Welcome {
30	    let body = page.find("<body>").expect("body opens") + "<body>".len();
31	    let banner = match page[body..].strip_prefix("<p class=\"message\">") {
32	        None => Banner::None,
33	        Some(rest) => {
34	            let (msg, _) = rest.split_once("</p>").expect("flash closes");
35	            match msg {
36	                "Loaded new theory!" => Banner::Loaded,
37	                "Post request failed." => Banner::Failed,
38	                other => Banner::Custom(unescape_entities(other)),
39	            }
40	        }
41	    };
42	    let vslot = "Tamarin</span></a> ";
43	    let vi = page.find(vslot).expect("version slot") + vslot.len();
44	    let version = &page[vi..vi + page[vi..].find("</div>").expect("version ends")];
45	    let ri = page.find("</thead>").expect("table head") + "</thead>".len();
46	    let rows_raw = &page[ri..ri + page[ri..].find("</table>").expect("table closes")];
47	    let mut rows = Vec::new();
48	    let mut rest = rows_raw;
49	    while !rest.is_empty() {
50	        let r = rest
51	            .strip_prefix("<tr><td><a href=\"/thy/trace/")
52	            .unwrap_or_else(|| panic!("row shape: {rest:?}"));
53	        let (idx, r) = r.split_once("/overview/help\">").expect("row href");
54	        let (name, r) = r.split_once("</a></td><td>").expect("row name cell");
55	        let (time, r) = r.split_once("</td><td>").expect("row time cell");
56	        let (vers, r) = r.split_once("</td><td>").expect("row version cell");
57	        let modified = match vers {
58	            "Original" => false,
59	            "<em>Modified" => true,
60	            other => panic!("version cell: {other:?}"),
61	        };
62	        let (origin, r) = r.split_once("</td></tr>").expect("row origin cell");
63	        rows.push(TheoryRow {
64	            index: idx.parse().expect("numeric row index"),
65	            name: unescape_entities(name),
66	            time: unescape_entities(time),
67	            modified,
68	            origin: unescape_entities(origin),
69	        });
70	        rest = r;
71	    }
72	    Welcome {
73	        version: unescape_entities(version),
74	        banner,
75	        rows,
76	    }
77	}
