20	/// Invert the per-line postprocess: split on `<br/>\n`, leading `&nbsp;` runs
21	/// back to spaces; assert the pane's final ` ` frame byte.
22	fn pane_lines(inner: &str) -> Vec<String> {
23	    let doc = inner
24	        .strip_suffix(' ')
25	        .expect("pane ends with the trailing space");
26	    assert!(doc.ends_with("<br/>\n"), "pane lines end with breaks");
27	    let mut lines: Vec<&str> = doc.split("<br/>\n").collect();
28	    assert_eq!(lines.pop(), Some(""), "trailing separator");
29	    lines
30	        .iter()
31	        .map(|line| {
32	            let mut rest = *line;
33	            let mut n = 0;
34	            while let Some(r) = rest.strip_prefix("&nbsp;") {
35	                rest = r;
36	                n += 1;
37	            }
38	            format!("{}{}", " ".repeat(n), rest)
39	        })
40	        .collect()
41	}
