43	/// Reverse of the producer's entity escape (strict).
44	pub fn unescape_entities(s: &str) -> String {
45	    let mut out = String::with_capacity(s.len());
46	    let mut rest = s;
47	    while let Some(i) = rest.find('&') {
48	        out.push_str(&rest[..i]);
49	        rest = &rest[i..];
50	        let (c, len) = if rest.starts_with("&amp;") {
51	            ('&', 5)
52	        } else if rest.starts_with("&lt;") {
53	            ('<', 4)
54	        } else if rest.starts_with("&gt;") {
55	            ('>', 4)
56	        } else if rest.starts_with("&quot;") {
57	            ('"', 6)
58	        } else if rest.starts_with("&#39;") {
59	            ('\'', 5)
60	        } else {
61	            panic!("unknown entity at {:?}", &rest[..rest.len().min(8)]);
62	        };
63	        out.push(c);
64	        rest = &rest[len..];
65	    }
66	    out.push_str(rest);
67	    out
68	}
