70	/// Escaped width as the layout rule measures it (tags 0, all else 1/char).
71	fn escaped_width(line: &str) -> usize {
72	    let mut w = 0;
73	    let mut in_tag = false;
74	    for c in line.chars() {
75	        match c {
76	            '<' => in_tag = true,
77	            '>' => in_tag = false,
78	            _ if !in_tag => w += 1,
79	            _ => {}
80	        }
81	    }
82	    w
83	}
