92	pub fn slice_pane(inner: &str) -> (u64, ProofScriptPane) {
93	    let lines = pane_lines(inner);
94	    let mut i = 0;
95	
96	    // 1. Header line.
97	    let rest = lines[0]
98	        .strip_prefix("<span class=\"hl_keyword\">theory</span> <a class=\"internal-link help\" href=\"/thy/trace/")
99	        .expect("theory header line");
100	    let (idx_str, rest) = rest.split_once("/main/help\">").expect("help href");
101	    let idx: u64 = idx_str.parse().expect("numeric index");
102	    let name = rest
103	        .strip_suffix("</a> <span class=\"hl_keyword\">begin</span>")
104	        .expect("begin keyword");
105	    let theory_name = unescape_entities(name);
106	    i += 1;
107	
108	    // 2. Item link lines (blank + item), until the add-first link.
109	    let mut items = Vec::new();
110	    loop {
111	        assert_eq!(lines[i], "", "blank before item/add line");
112	        if lines[i + 1].starts_with("<a class=\"internal-link add\"") {
113	            break;
114	        }
115	        let it = lines[i + 1]
116	            .strip_prefix(&format!("<a class=\"internal-link\" href=\"/thy/trace/{idx}/main/"))
117	            .unwrap_or_else(|| panic!("item line shape: {:?}", lines[i + 1]));
118	        let (tail, it) = it.split_once("\"><strong>").expect("item strong open");
119	        let (label, it) = it.split_once("</strong> ").expect("item strong close");
120	        let annotation = it.strip_suffix("</a>").expect("item anchor close");
121	        let target = parse_path(tail).expect("item target parses");
122	        // The link is canonical: R5 re-renders it byte-identically.
123	        items.push(NavItem {
124	            target,
125	            label: label.to_string(),
126	            annotation: annotation.to_string(),
127	        });
128	        i += 2;
129	    }
130	    // 3. The add-first link.
131	    assert_eq!(
132	        lines[i + 1],
133	        format!("<a class=\"internal-link add\" href=\"/thy/trace/{idx}/main/add/%3Cfirst%3E\">add lemma</a>"),
134	        "add-first link"
135	    );
136	    i += 2;
137	
138	    // 4. Lemma blocks; 5. end.
139	    let mut lemmas = Vec::new();
140	    loop {
141	        assert_eq!(lines[i], "", "blank before lemma/end");
142	        i += 1;
143	        if lines[i] == KW_END {
144	            assert_eq!(i, lines.len() - 1, "end is the last line");
145	            break;
146	        }
147	        if lines[i].is_empty() && lines[i + 1] == KW_END {
148	            // Zero-lemma pane: two blanks before `end`.
149	            assert!(lemmas.is_empty());
150	            assert_eq!(i + 1, lines.len() - 1, "end is the last line");
151	            break;
152	        }
153	
154	        // 4a. Declaration line(s), with optional status wrapper.
155	        let (wrapper, decl_rest) = match lines[i].strip_prefix(KW_LEMMA) {
156	            Some(rest) => (None, rest.to_string()),
157	            None => {
158	                let w = lines[i]
159	                    .strip_prefix("<span class=\"")
160	                    .unwrap_or_else(|| panic!("decl line shape: {:?}", lines[i]));
161	                let (class, rest) = w.split_once("\">").expect("wrapper span open");
162	                let rest = rest.strip_prefix(KW_LEMMA).expect("lemma keyword after wrapper");
163	                (Some(class.to_string()), rest.to_string())
164	            }
165	        };
166	        let mut decl = decl_rest;
167	        while !decl.ends_with(':') {
168	            i += 1;
169	            decl.push('\n');
170	            decl.push_str(&lines[i]);
171	        }
172	        i += 1;
173	        let decl = decl.strip_suffix(':').unwrap();
174	        let (name_html, attributes) = match decl.find(" [") {
175	            Some(p) => (&decl[..p], &decl[p..]),
176	            None => (decl, ""),
177	        };
178	        let name = unescape_entities(name_html);
179	
180	        // 4b. Quantifier / formula block at indent 2.
181	        let q = lines[i]
182	            .strip_prefix("  ")
183	            .unwrap_or_else(|| panic!("quantifier indent: {:?}", lines[i]));
184	        let (quantifier, formula_lines) = if let Some((kw, rest)) = q.split_once(' ') {
185	            assert!(matches!(kw, "all-traces" | "exists-trace"), "quantifier {kw:?}");
186	            // Inline layout: the assembled line obeys the width limit.
187	            assert!(
188	                escaped_width(&lines[i]) <= 69,
189	                "inline line wider than 69: {:?}",
190	                lines[i]
191	            );
192	            i += 1;
193	            (kw.to_string(), vec![rest.to_string()])
194	        } else {
195	            assert!(matches!(q, "all-traces" | "exists-trace"), "quantifier {q:?}");
196	            let kw = q.to_string();
197	            i += 1;
198	            let mut fl = Vec::new();
199	            while !lines[i].starts_with("<a class=\"internal-link edit\"") {
200	                let l = lines[i]
201	                    .strip_prefix("  ")
202	                    .unwrap_or_else(|| panic!("formula indent: {:?}", lines[i]));
203	                fl.push(l.to_string());
204	                i += 1;
205	            }
206	            // Vertical layout is justified: multi-line, or over the limit.
207	            if let [only] = fl.as_slice() {
208	                assert!(
209	                    escaped_width(&format!("  {kw} {only}")) > 69,
210	                    "single-line formula under the limit rendered vertically"
211	                );
212	            }
213	            (kw, fl)
214	        };
215	
216	        // 4c. Edit-or-delete line (closes the wrapper span when present).
217	        let e = lines[i]
218	            .strip_prefix(&format!("<a class=\"internal-link edit\" href=\"/thy/trace/{idx}/main/edit/"))
219	            .unwrap_or_else(|| panic!("edit line shape: {:?}", lines[i]));
220	        let (enc_name, e) = e.split_once("\">edit lemma</a>  or  ").expect("or separator");
221	        let e = e
222	            .strip_prefix(&format!("<a class=\"internal-link delete\" href=\"/thy/trace/{idx}/main/delete/"))
223	            .expect("delete anchor");
224	        let (_enc2, e) = e.split_once("\">delete lemma</a>").expect("delete anchor close");
225	        match wrapper {
226	            Some(_) => assert_eq!(e, "</span>", "wrapper closes after delete anchor"),
227	            None => assert_eq!(e, "", "no wrapper close on a bare header"),
228	        }
229	        i += 1;
230	
231	        // 4d. Proof display: the exact sorry step, or a structured proof tree
232	        // (only the per-node method text stays opaque).
233	        let sorry_line = format!(
234	            "<span class=\"hl_keyword\">by</span> <a class=\"internal-link proof-step sorry-step\" href=\"/thy/trace/{idx}/main/proof/{enc_name}\"><span class=\"hl_keyword\">sorry</span></a>"
235	        );
236	        let proof = if lines[i] == sorry_line {
237	            assert!(wrapper.is_none(), "sorry proof has no header wrapper");
238	            i += 1;
239	            ProofDisplay::Unproven
240	        } else {
241	            let mut pl = Vec::new();
242	            while !lines[i].is_empty() {
243	                pl.push(lines[i].clone());
244	                i += 1;
245	            }
246	            let mut inv = TreeInv {
247	                lines: &pl,
248	                pos: 0,
249	                idx,
250	                lemma: &name,
251	            };
252	            let root = inv.node(0, &mut Vec::new());
253	            assert_eq!(inv.pos, pl.len(), "proof display fully consumed");
254	            // The lemma-header wrapper is exactly the root's status class.
255	            assert_eq!(
256	                wrapper.as_deref(),
257	                class_of(&root.status),
258	                "header wrapper matches proof root status"
259	            );
260	            ProofDisplay::Tree(root)
261	        };
262	
263	        // 4e. Blank + this lemma's add link.
264	        assert_eq!(lines[i], "", "blank after proof display");
265	        assert_eq!(
266	            lines[i + 1],
267	            format!("<a class=\"internal-link add\" href=\"/thy/trace/{idx}/main/add/{enc_name}\">add lemma</a>"),
268	            "per-lemma add link"
269	        );
270	        i += 2;
271	
272	        lemmas.push(LemmaEntry {
273	            name,
274	            attributes: attributes.to_string(),
275	            quantifier,
276	            formula: Content { lines: formula_lines },
277	            proof,
278	        });
279	    }
280	
281	    (
282	        idx,
283	        ProofScriptPane {
284	            theory_name,
285	            index: idx,
286	            items,
287	            lemmas,
288	        },
289	    )
290	}
