318	const KW_BY: &str = "<span class=\"hl_keyword\">by</span> ";
319	
320	fn indent_of(line: &str) -> usize {
321	    line.len() - line.trim_start_matches(' ').len()
322	}
323	
324	/// `Some((status, rest))` when `s` opens with a possibly-wrapped keyword
325	/// structural line (`case ` tail returned; `next`/`qed` return `""`).
326	fn keyword_line(s: &str, kw: &str) -> Option<(Option<String>, String)> {
327	    let bare = format!("<span class=\"hl_keyword\">{kw}</span>");
328	    if let Some(rest) = s.strip_prefix(&bare) {
329	        // Bare (status-less) form: `case NAME` / whole-line `next` / `qed`.
330	        return match rest.strip_prefix(' ') {
331	            Some(name) => Some((None, name.to_string())),
332	            None if rest.is_empty() => Some((None, String::new())),
333	            _ => None,
334	        };
335	    }
336	    let w = s.strip_prefix("<span class=\"")?;
337	    let (cls, rest) = w.split_once("\">")?;
338	    let rest = rest.strip_prefix(&bare)?;
339	    let inner = rest.strip_suffix("</span>")?;
340	    match inner.strip_prefix(' ') {
341	        Some(name) => Some((Some(cls.to_string()), name.to_string())),
342	        None if inner.is_empty() => Some((Some(cls.to_string()), String::new())),
343	        _ => None,
344	    }
345	}
