347	/// One parsed step line: the `by ` prefix's wrapper (outer `Option` = prefix
348	/// present), the anchor/span status class, remove-step presence, the href for
349	/// an anchored step, and the opaque method text.
350	struct StepItem {
351	    indent: usize,
352	    by: Option<Option<String>>,
353	    status: Option<String>,
354	    anchored: bool,
355	    removable: bool,
356	    href: Option<String>,
357	    method: String,
358	}
359	
360	/// Strict recursive-descent inversion of a proof display into a
361	/// [`ProofTree`], asserting every frame byte, status placement and link
362	/// target on the way.
363	struct TreeInv<'a> {
364	    lines: &'a [String],
365	    pos: usize,
366	    idx: u64,
367	    lemma: &'a str,
368	}
369	
370	impl TreeInv<'_> {
371	    /// Classify the line at `pos` without consuming (case/next/qed/step).
372	    fn peek(&self) -> Option<(&'static str, usize, Option<String>, String)> {
373	        let line = self.lines.get(self.pos)?;
374	        let ind = indent_of(line);
375	        let rest = &line[ind..];
376	        for kw in ["case", "next", "qed"] {
377	            if let Some((st, tail)) = keyword_line(rest, kw) {
378	                return Some((kw, ind, st, tail));
379	            }
380	        }
381	        Some(("step", ind, None, String::new()))
382	    }
383	
384	    /// Parse the step item starting at `pos` (consuming the method text's
385	    /// continuation lines).
386	    fn step(&mut self) -> StepItem {
387	        let line = &self.lines[self.pos];
388	        let indent = indent_of(line);
389	        let mut rest = line[indent..].to_string();
390	        // Optional `by ` prefix, bare or status-wrapped.
391	        let by = if let Some(r) = rest.strip_prefix(KW_BY) {
392	            let r = r.to_string();
393	            rest = r;
394	            Some(None)
395	        } else if let Some(w) = rest.strip_prefix("<span class=\"") {
396	            match w.split_once("\">") {
397	                Some((cls, r)) if r.starts_with(KW_BY) => {
398	                    let r = r
399	                        .strip_prefix(KW_BY)
400	                        .unwrap()
401	                        .strip_prefix("</span>")
402	                        .expect("wrapped by-prefix closes");
403	                    let cls = cls.to_string();
404	                    rest = r.to_string();
405	                    Some(Some(cls))
406	                }
407	                _ => None,
408	            }
409	        } else {
410	            None
411	        };
412	        if let Some(a) = rest.strip_prefix("<a class=\"internal-link proof-step ") {
413	            // Anchored step: slice the href, then the method up to `</a>`.
414	            let (cls, a) = a.split_once("\" href=\"").expect("proof-step href");
415	            let (href, a) = a.split_once("\">").expect("href close");
416	            let status = match cls {
417	                "sorry-step" => None,
418	                other => Some(other.to_string()),
419	            };
420	            let (method, tail) = self.until(a.to_string(), "</a>");
421	            let removable = !tail.is_empty();
422	            if removable {
423	                let t = tail
424	                    .strip_prefix("<a class=\"internal-link remove-step\" href=\"")
425	                    .unwrap_or_else(|| panic!("remove-step follows: {tail:?}"));
426	                let t = t.strip_prefix(href).expect("remove-step href matches");
