451	            'span: loop {
452	                let mut i = 0;
453	                loop {
454	                    match (body[i..].find("<span"), body[i..].find("</span>")) {
455	                        (Some(o), Some(c)) if o < c => {
456	                            depth += 1;
457	                            i += o + 5;
458	                        }
459	                        (_, Some(c)) => {
