520	    /// Parse one node (step + case layout) at `depth`, path `sub`.
521	    fn node(&mut self, depth: usize, sub: &mut Vec<String>) -> ProofTree {
522	        let st = self.step();
523	        assert_eq!(st.indent, depth, "step at its node's indent");
524	        if st.href.is_some() {
525	            let want = format!(
526	                "/thy/trace/{}/main/{}",
527	                self.idx,
528	                render_path(&ThyPath::Proof {
529	                    lemma: self.lemma.to_string(),
530	                    sub: sub.clone(),
531	                })
532	                .join("/")
533	            );
534	            assert_eq!(st.href.as_deref(), Some(want.as_str()), "canonical step href");
535	        }
536	        if let Some(by_cls) = &st.by {
537	            assert_eq!(by_cls.as_deref(), st.status.as_deref(), "by wrapper = step status");
538	        }
539	        let status = hl_of(st.status.as_deref());
540	        if !st.anchored {
541	            assert!(
542	                matches!(status, Highlight::Replayed),
543	                "span-only steps carry the replayed status"
544	            );
545	        }
546	        let mut cases: Vec<(String, ProofTree)> = Vec::new();
547	        match self.peek() {
548	            Some(("step", ind, _, _)) if ind == depth => {
549	                // Single unnamed continuation at the same indent.
550	                assert!(st.by.is_none(), "a closed (by) step has no continuation");
551	                sub.push("_".to_string());
552	                let child = self.node(depth, sub);
553	                sub.pop();
554	                cases.push((String::new(), child));
555	            }
556	            Some(("case", ind, _, _)) if ind == depth + 2 => loop {
557	                let (kw, ind, case_st, name) = self.peek().unwrap();
558	                assert_eq!((kw, ind), ("case", depth + 2), "case at parent indent + 2");
559	                assert!(!name.is_empty() && !name.contains('<'), "plain case name");
560	                self.pos += 1;
561	                sub.push(name.clone());
562	                let child = self.node(depth + 2, sub);
563	                sub.pop();
564	                assert_eq!(
565	                    case_st.as_deref(),
566	                    class_of(&child.status),
567	                    "case line carries the child's status"
568	                );
569	                cases.push((name, child));
570	                match self.peek() {
571	                    Some(("next", i2, nst, _)) if i2 == depth => {
572	                        assert_eq!(
573	                            nst.as_deref(),
574	                            st.status.as_deref(),
575	                            "next carries the parent's status"
576	                        );
577	                        self.pos += 1;
578	                    }
579	                    Some(("qed", i2, qst, _)) if i2 == depth => {
580	                        assert_eq!(
581	                            qst.as_deref(),
582	                            st.status.as_deref(),
583	                            "qed carries the parent's status"
584	                        );
585	                        self.pos += 1;
586	                        break;
587	                    }
588	                    other => panic!("expected next/qed at indent {depth}, got {other:?}"),
589	                }
590	            },
591	            _ => {}
592	        }
593	        if !cases.is_empty() {
594	            assert!(st.by.is_none(), "a node with cases has no by prefix");
595	        }
596	        // Removability, as observed corpus-wide: every step carries the
597	        // remove-step anchor (replayed leftovers included) EXCEPT the sorry
598	        // slots — the status-less steps with no real (non-replayed)
599	        // continuation.
600	        match (&status, st.anchored) {
601	            (Highlight::Replayed, false) => {
602	                assert!(st.removable, "replayed steps keep the remove affordance")
603	            }
604	            (Highlight::None, true) => {
605	                let has_real_child = cases
606	                    .iter()
607	                    .any(|(_, c)| !matches!(c.status, Highlight::Replayed));
608	                assert_eq!(st.removable, has_real_child, "sorry slots are not removable");
609	            }
610	            (_, true) => assert!(st.removable, "anchored non-sorry steps are removable"),
611	            (st2, false) => panic!("span-only step with status {:?}", class_of(st2)),
612	        }
613	        ProofTree {
614	            method_text: st.method,
615	            status,
616	            live: st.removable,
617	            terminal_marker: cases.is_empty() && st.by.is_none(),
618	            cases,
619	        }
620	    }
621	}
